// =================================================================
// 3d-filament daily stock crawler — Code node logic
// Mirrors scripts/crawl-stock.mjs in the repo. Keep them in sync.
// =================================================================

const IN_PATTERNS = [
  /є\s+в\s+наявн/iu,
  /в\s+наявності/iu,
  /є\s+на\s+склад/iu,
  /available/i,
  /in\s+stock/i,
];
const OUT_PATTERNS = [
  /немає\s+в\s+наявн/iu,
  /не\s+в\s+наявн/iu,
  /відсутн/iu,
  /під\s+замовлення/iu,
  /очікуєт/iu,
  /закінчив/iu,
  /out\s+of\s+stock/i,
  /sold\s+out/i,
];
const STRIP_TAGS = /<(script|style|noscript)[\s\S]*?<\/\1>/gi;
const WINDOW = 200;
const OVERRIDES = {};

function escapeRegex(s) { return s.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'); }

function detectMaterialStatus(html, material) {
  const needle = new RegExp(`\\b${escapeRegex(material)}\\b`, 'giu');
  let match, sawIn = false, sawOut = false, sawAny = false;
  while ((match = needle.exec(html)) !== null) {
    sawAny = true;
    const start = Math.max(0, match.index - WINDOW);
    const end = Math.min(html.length, match.index + match[0].length + WINDOW);
    const ctx = html.slice(start, end);
    if (OUT_PATTERNS.some(re => re.test(ctx))) sawOut = true;
    else if (IN_PATTERNS.some(re => re.test(ctx))) sawIn = true;
    if (sawIn) break;
  }
  if (!sawAny) return 'unknown';
  if (sawIn) return 'in';
  if (sawOut) return 'out';
  return 'unknown';
}

function parseStock(html, materials, companyId) {
  const cleaned = String(html).replace(STRIP_TAGS, ' ');
  const result = {};
  const override = OVERRIDES[companyId] ? OVERRIDES[companyId](cleaned, materials) || {} : {};
  for (const m of materials) result[m] = override[m] || detectMaterialStatus(cleaned, m);
  return result;
}

// HTTP node may emit companies as one item (array) or many items (one per company).
const items = $input.all();
let companies;
if (items.length === 1 && Array.isArray(items[0].json)) companies = items[0].json;
else if (items.length === 1 && Array.isArray(items[0].json.data)) companies = items[0].json.data;
else companies = items.map(i => i.json);

const UA = 'Mozilla/5.0 (compatible; 3d-filament-stock-bot/1.0; +https://3d-filament.pages.dev)';
const out = { lastChecked: new Date().toISOString(), companies: {} };

for (const c of companies) {
  const checkedAt = new Date().toISOString();
  try {
    const html = await this.helpers.httpRequest({
      method: 'GET',
      url: c.url,
      headers: { 'User-Agent': UA, 'Accept-Language': 'uk,en;q=0.8' },
      timeout: 15000,
      json: false,
      returnFullResponse: false,
    });
    out.companies[c.id] = { ...parseStock(html, c.materials, c.id), checkedAt };
  } catch (err) {
    out.companies[c.id] = { _error: String(err.message || err), checkedAt };
  }
  await new Promise(r => setTimeout(r, 1500));
}

const json = JSON.stringify(out, null, 2) + '\n';
const date = out.lastChecked.slice(0, 10);
const summary = Object.entries(out.companies).map(([id, s]) => {
  if (s._error) return `${id}: ERROR (${s._error})`;
  const counts = { in: 0, out: 0, unknown: 0 };
  for (const [k, v] of Object.entries(s)) if (k !== 'checkedAt') counts[v] = (counts[v] || 0) + 1;
  return `${id}: ${counts.in} in / ${counts.out} out / ${counts.unknown} unknown`;
}).join('\n');

return [{ json: { content: json, commitMessage: `chore(stock): daily update ${date}`, summary } }];
